for c in message:
    swapped = c.swapcase()
    if swapped.lower() in vowels:
        base = ord('A') if swapped.isupper() else ord('a')
        offset = ord(swapped) - base
        new_char = chr(base + (offset + 2) % 26)
        res.append(new_char)
    else:
        res.append(swapped)
return ''.join(res)
